if (!Array.isArray($input.all()) || $input.all().length === 0) {
  throw new Error("No input data received");
}

const firstItem = $input.all()[0].json;

if (!firstItem.body || !firstItem.body.workflow) {
  throw new Error("Workflow not found in body");
}

return [
  {
    json: firstItem.body.workflow
  }
];

// Ensure input exists
const items = $input.all();

if (!items.length) {
  throw new Error("No input received");
}

// Get first item
const firstItem = items[0].json;

// Validate output field
if (!firstItem.output) {
  throw new Error("Missing 'output' field");
}

let rawOutput = firstItem.output;

// Ensure it is a string
if (typeof rawOutput !== "string") {
  throw new Error("Output is not a string");
}

// Trim possible whitespace
rawOutput = rawOutput.trim();

// Remove accidental markdown wrapping if AI added it
if (rawOutput.startsWith("```")) {
  rawOutput = rawOutput.replace(/```json|```/g, "").trim();
}

// Parse JSON safely
let parsedWorkflow;

try {
  parsedWorkflow = JSON.parse(rawOutput);
} catch (error) {
  throw new Error("Invalid JSON returned by AI: " + error.message);
}

// Optional: Basic structural validation
if (!parsedWorkflow.nodes || !parsedWorkflow.connections) {
  throw new Error("Parsed JSON is not a valid n8n workflow structure");
}

// Return normalized workflow object
return [
  {
    json: parsedWorkflow
  }
];
